// NQxb_Messaging__Normalize_Request
// Extract and normalize messaging.send_email fields from Execute Workflow input
// v1.1: Fixed crypto.randomUUID() → Math.random UUID (n8n sandbox compatible)

const raw = $json ?? {};

// Generate trace_id for this dispatch (n8n sandbox does not expose crypto)
const trace_id = 'msg_' + 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
  const r = Math.random() * 16 | 0;
  return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
});

const normalized = {
  // Identity
  gw_action: (raw.gw_action ?? '').toString().trim(),
  gw_workspace_id: (raw.gw_workspace_id ?? '').toString().trim(),
  trace_id: trace_id,

  // Required fields
  to: Array.isArray(raw.to) ? raw.to : [],
  subject: (raw.subject ?? '').toString().trim(),
  body_html: raw.body_html ?? null,
  body_text: raw.body_text ?? null,

  // Optional fields
  cc: Array.isArray(raw.cc) ? raw.cc : [],
  bcc: Array.isArray(raw.bcc) ? raw.bcc : [],
  reply_to: raw.reply_to ?? null,
  tags: Array.isArray(raw.tags) ? raw.tags : [],
  parent_artifact_id: raw.parent_artifact_id ?? null,

  // Semantic type for artifact save
  semantic_type_id: raw.semantic_type_id ?? 'f458c86a-e037-4c48-a4a2-ce228546957f',
};

return [{ json: normalized }];

// NQxb_Messaging__Validate_Payload
// Validation rules per contract 2cbc7f05
// Fail-fast: returns first error only
// v1.0: Initial implementation

const req = $json;

// Email regex (basic RFC 5322)
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

// --- Validation rules (fail-fast) ---

// 1. gw_action
if (req.gw_action !== 'messaging.send_email') {
  return [{ json: { valid: false, error_code: 'VALIDATION_ERROR', error_message: 'invalid gw_action', error_field: 'gw_action', ...req } }];
}

// 2. gw_workspace_id
if (!req.gw_workspace_id || !uuidRegex.test(req.gw_workspace_id)) {
  return [{ json: { valid: false, error_code: 'VALIDATION_ERROR', error_message: 'missing or invalid gw_workspace_id', error_field: 'gw_workspace_id', ...req } }];
}

// 3. to — required, non-empty array, valid emails
if (!Array.isArray(req.to) || req.to.length === 0) {
  return [{ json: { valid: false, error_code: 'VALIDATION_ERROR', error_message: 'to must be non-empty array of valid email addresses', error_field: 'to', ...req } }];
}
for (const addr of req.to) {
  if (typeof addr !== 'string' || !emailRegex.test(addr.trim())) {
    return [{ json: { valid: false, error_code: 'VALIDATION_ERROR', error_message: `to contains invalid email: ${addr}`, error_field: 'to', ...req } }];
  }
}

// 4. subject — required, non-empty
if (typeof req.subject !== 'string' || req.subject.trim() === '') {
  return [{ json: { valid: false, error_code: 'VALIDATION_ERROR', error_message: 'missing subject', error_field: 'subject', ...req } }];
}

// 5. body_html or body_text — at least one required
const hasHtml = typeof req.body_html === 'string' && req.body_html.trim() !== '';
const hasText = typeof req.body_text === 'string' && req.body_text.trim() !== '';
if (!hasHtml && !hasText) {
  return [{ json: { valid: false, error_code: 'VALIDATION_ERROR', error_message: 'at least one of body_html or body_text required', error_field: 'body_html / body_text', ...req } }];
}

// 6. cc — optional, valid emails if present
if (req.cc && req.cc.length > 0) {
  for (const addr of req.cc) {
    if (typeof addr !== 'string' || !emailRegex.test(addr.trim())) {
      return [{ json: { valid: false, error_code: 'VALIDATION_ERROR', error_message: `cc contains invalid email: ${addr}`, error_field: 'cc', ...req } }];
    }
  }
}

// 7. bcc — optional, valid emails if present
if (req.bcc && req.bcc.length > 0) {
  for (const addr of req.bcc) {
    if (typeof addr !== 'string' || !emailRegex.test(addr.trim())) {
      return [{ json: { valid: false, error_code: 'VALIDATION_ERROR', error_message: `bcc contains invalid email: ${addr}`, error_field: 'bcc', ...req } }];
    }
  }
}

// 8. reply_to — optional, valid email if present
if (req.reply_to !== null && req.reply_to !== undefined) {
  if (typeof req.reply_to !== 'string' || !emailRegex.test(req.reply_to.trim())) {
    return [{ json: { valid: false, error_code: 'VALIDATION_ERROR', error_message: 'invalid reply_to email', error_field: 'reply_to', ...req } }];
  }
}

// 9. tags — optional, must be array of strings
if (req.tags && req.tags.length > 0) {
  for (const t of req.tags) {
    if (typeof t !== 'string') {
      return [{ json: { valid: false, error_code: 'VALIDATION_ERROR', error_message: 'tags must be array of strings', error_field: 'tags', ...req } }];
    }
  }
}

// 10. parent_artifact_id — optional, valid UUID if present
if (req.parent_artifact_id !== null && req.parent_artifact_id !== undefined) {
  if (typeof req.parent_artifact_id !== 'string' || !uuidRegex.test(req.parent_artifact_id)) {
    return [{ json: { valid: false, error_code: 'VALIDATION_ERROR', error_message: 'invalid parent_artifact_id format', error_field: 'parent_artifact_id', ...req } }];
  }
}

// All valid
return [{ json: { valid: true, ...req } }];

// NQxb_Messaging__Build_Dispatch_Response
// Build internal dispatch response per contract 721cfe50
// Extract provider_metadata from Gmail response
// v1.0: Initial implementation

const gmailResponse = $json;
const request = $node['NQxb_Messaging__Normalize_Request'].json;

// Check if Gmail returned an error
if (gmailResponse.error || gmailResponse.statusCode >= 400) {
  // Provider dispatch failed
  const errorMsg = gmailResponse.error?.message
    ?? gmailResponse.message
    ?? JSON.stringify(gmailResponse).substring(0, 500);

  return [{ json: {
    dispatch_ok: false,
    gw_action: 'messaging.send_email',
    provider: 'gmail',
    error_code: 'PROVIDER_DISPATCH_FAILED',
    error_message: `Gmail API error: ${errorMsg}`.substring(0, 500),
    timestamp: new Date().toISOString(),
    trace_id: request.trace_id,
    // Carry forward request data for error response
    _request: request,
  }}];
}

// Success — extract provider metadata per contract 60c2bdf0
const message_id = gmailResponse.id ?? null;
const thread_id = gmailResponse.threadId ?? null;

return [{ json: {
  dispatch_ok: true,
  gw_action: 'messaging.send_email',
  provider: 'gmail',
  timestamp: new Date().toISOString(),
  trace_id: request.trace_id,
  provider_metadata: {
    message_id: message_id,
    thread_id: thread_id,
  },
  request_echo: {
    to: request.to,
    subject: request.subject,
  },
  // Carry forward for artifact save
  _request: request,
}}];

// NQxb_Messaging__Check_Dispatch
// Route based on dispatch_ok: true → save artifact, false → error
// v1.0

const dispatch = $json;

if (dispatch.dispatch_ok === true) {
  // Continue to artifact save
  return [{ json: dispatch }];
}

// Dispatch failed — route to error shaper
// Return empty array for this output, data goes via second output
return [];

// NQxb_Messaging__Check_Save
// Verify both spine and extension saves succeeded
// v1.0

const spineResult = $node['NQxb_Messaging__Save_Spine'].json;
const extResult = $json; // extension save result
const dispatch = $node['NQxb_Messaging__Build_Dispatch_Response'].json;

// Check if spine save returned an artifact_id
const spineData = Array.isArray(spineResult) ? spineResult[0] : spineResult;
const artifact_id = spineData?.artifact_id ?? null;

if (!artifact_id) {
  // Spine save failed
  return [{ json: {
    save_ok: false,
    dispatch: dispatch,
  }}];
}

// Check extension save
const extData = Array.isArray(extResult) ? extResult[0] : extResult;
if (extData?.error || extData?.statusCode >= 400) {
  return [{ json: {
    save_ok: false,
    dispatch: dispatch,
    artifact_id: artifact_id,
  }}];
}

// Both succeeded
return [{ json: {
  save_ok: true,
  artifact_id: artifact_id,
  dispatch: dispatch,
}}];

// NQxb_Messaging__Shape_Success
// Build Gateway success envelope per contract aeca3c25
// v1.0

const data = $json;
const dispatch = data.dispatch;

return [{ json: {
  ok: true,
  gw_action: 'messaging.send_email',
  artifact_id: data.artifact_id,
  timestamp: new Date().toISOString(),
  trace_id: dispatch.trace_id,
  provider_metadata: dispatch.provider_metadata,
}}];

// NQxb_Messaging__Shape_Error
// Build Gateway error envelope
// Handles: VALIDATION_ERROR, PROVIDER_DISPATCH_FAILED, ARTIFACT_SAVE_FAILED
// v1.0

const data = $json;

// Determine which error path we came from

// Path 1: Validation error (from Check_Validation false branch)
if (data.error_code === 'VALIDATION_ERROR') {
  return [{ json: {
    ok: false,
    _gw_route: 'error',
    error: {
      code: 'VALIDATION_ERROR',
      message: data.error_message,
      details: {
        gw_action: 'messaging.send_email',
        field: data.error_field ?? null,
        rule: data.error_message,
        trace_id: data.trace_id,
      },
    },
  }}];
}

// Path 2: Provider dispatch failed (from Build_Dispatch_Response with dispatch_ok=false)
if (data.dispatch_ok === false) {
  return [{ json: {
    ok: false,
    _gw_route: 'error',
    error: {
      code: 'PROVIDER_DISPATCH_FAILED',
      message: data.error_message,
      details: {
        gw_action: 'messaging.send_email',
        provider: 'gmail',
        provider_status: data.provider_status ?? null,
        provider_message: (data.error_message ?? '').substring(0, 500),
        trace_id: data.trace_id,
      },
    },
  }}];
}

// Path 3: Artifact save failed (from Check_Save with save_ok=false)
if (data.save_ok === false) {
  const dispatch = data.dispatch ?? {};
  return [{ json: {
    ok: false,
    _gw_route: 'error',
    error: {
      code: 'ARTIFACT_SAVE_FAILED',
      message: 'Message sent successfully but artifact record failed to save',
      details: {
        gw_action: 'messaging.send_email',
        dispatch_succeeded: true,
        provider_metadata: dispatch.provider_metadata ?? null,
        trace_id: dispatch.trace_id ?? null,
      },
    },
  }}];
}

// Fallback (should not reach here)
return [{ json: {
  ok: false,
  _gw_route: 'error',
  error: {
    code: 'UNKNOWN_ERROR',
    message: 'Unexpected error in messaging workflow',
    details: data,
  },
}}];
